def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def calculate_penalty(arrival_time, time_window):
        if arrival_time > time_window[1]:
            return (arrival_time - time_window[1]) * 2
        elif arrival_time < time_window[0]:
            return (time_window[0] - arrival_time)
        else:
            return 0

    best_node = None
    min_score = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        for j, truck_pos in enumerate(all_truck_pos):
            time_to_customer = np.linalg.norm(customer_pos - truck_pos) / truck_speed
            arrival_time = current_time + time_to_customer
            penalty = calculate_penalty(arrival_time, time_windows[i])

            if arrival_time < time_windows[i][1]:
                score = penalty + (arrival_time - current_time)
            else:
                score = penalty + (arrival_time - current_time) * 1.5

            if score < min_score:
                min_score = score
                best_node = i

    return best_node
